&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; ioi的数据结构题，果然还是比较BT的。&lt;/p&gt; &nbsp;
做法是对颜色分开，大的颜色预处理，小的颜色直接暴力。
&nbsp;
然后一个小错又坑了好久。我真的没救了。
#include &lt;cstdio&gt; #include &lt;cstdlib&gt; #include &lt;cctype&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; using namespace std;
const int buf_len = 4000; const size_t buf_size = buf_len * sizeof(char); char buf[buf_len], *bufb(buf), *bufe(buf + 1); #define readBuf() { if (++ bufb == bufe) bufe = (bufb = buf) + fread(buf, 1, buf_size, stdin); } #define readInt(x) { register int s(0); do { readBuf(); } while (!isdigit(*bufb)); do { s = s * 10 + *bufb - 48; readBuf(); } while (isdigit(*bufb)); x = s; }

&lt;div class=&quot;post_brief&quot;&gt;&lt;p&gt; 听说是水水的splay，果然是。&lt;/p&gt; &nbsp;
乍一看要用lct，然后因为度数只有2，所以肯定是一条链。然后就直接用splay来维护。然后因为少写了句splay(v)导致多调了至少一节课的时间。我没救了。
#include &lt;cstdio&gt; #include &lt;cstring&gt; #include &lt;algorithm&gt; #include &lt;map&gt; using namespace std;
#define upmax(a,b) { if (a &lt; b) a = b; }
struct splay_node { int vl, vm, rv; splay_node *pt, *ls, *rs; inline void update() { vm = vl; if (ls) upmax(vm, ls-&gt; vm); if (rs) upmax(vm, rs-&gt; vm); } inline void fix() { if (rv) { swap(ls, rs); if (ls) ls-&gt; rv ^= 1; if (rs) rs-&gt; rv ^= 1; rv = 0; } } };

